import{_ as e}from"./plugin-vue_export-helper-DlAUqK2U.js";import{c as p,a as s,e as t,r as o,o as c}from"./app-SX1WwGPK.js";const l={};function i(u,n){const a=o("Mermaid");return c(),p("div",null,[n[0]||(n[0]=s('<h2 id="引言" tabindex="-1"><a class="header-anchor" href="#引言"><span>引言</span></a></h2><p>一个读多写少的 List，用 synchronized 加锁就完了？</p><p>加锁确实能保证线程安全，但代价是所有操作都串行化——读操作也要排队等待写操作释放锁。在读远多于写的场景下（如配置列表、白名单、路由表），这是不必要的性能浪费。</p><p><code>CopyOnWriteArrayList</code> 提供了一种更优雅的思路：<strong>写时复制</strong>。读操作完全无锁、零等待，写操作在副本上进行、完成后原子替换引用。这意味着读操作的性能等同于普通 ArrayList，唯一的代价是写操作需要额外分配内存。</p><p>本文将从源码级别剖析 CopyOnWriteArrayList 的核心设计，带你理解：</p><ol><li>CopyOnWriteArrayList 的写时复制机制（ReentrantLock + 数组拷贝 + volatile 引用替换）</li><li>为什么读操作完全无锁？弱一致性的迭代器设计</li><li>适用场景与性能陷阱（大数组写操作、内存峰值）</li></ol><h2 id="简介" tabindex="-1"><a class="header-anchor" href="#简介"><span>简介</span></a></h2><p><code>CopyOnWriteArrayList</code> 是一种线程安全的 <code>ArrayList</code>，底层基于数组实现，该数组使用了 <code>volatile</code> 关键字修饰。</p><p>实现线程安全的原理是&quot;人如其名&quot;——<strong>Copy On Write（写时复制）</strong>。在对其进行修改操作时，复制一个新的数组，在新数组上进行修改，最后用新数组替换旧数组的引用。这样读操作始终在旧数组上进行，不会被写操作干扰。</p><h3 id="类图架构" tabindex="-1"><a class="header-anchor" href="#类图架构"><span>类图架构</span></a></h3>',10)),t(a,{id:"mermaid-44",code:""}),n[1]||(n[1]=s(`<p>看一下 <code>CopyOnWriteArrayList</code> 内部有哪些数据结构组成：</p><div class="language-java line-numbers-mode" data-ext="java" data-title="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">CopyOnWriteArrayList</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">E</span><span class="token punctuation">&gt;</span></span>
    <span class="token keyword">implements</span> <span class="token class-name">List</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">E</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">,</span> <span class="token class-name">RandomAccess</span><span class="token punctuation">,</span> <span class="token class-name">Cloneable</span><span class="token punctuation">,</span> <span class="token class-name"><span class="token namespace">java<span class="token punctuation">.</span>io<span class="token punctuation">.</span></span>Serializable</span> <span class="token punctuation">{</span>

    <span class="token comment">// 排它锁，用来保证写操作的线程安全</span>
    <span class="token keyword">final</span> <span class="token keyword">transient</span> <span class="token class-name">ReentrantLock</span> lock <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">ReentrantLock</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

    <span class="token comment">// 存储元素的数组，使用 volatile 修饰</span>
    <span class="token keyword">private</span> <span class="token keyword">transient</span> <span class="token keyword">volatile</span> <span class="token class-name">Object</span><span class="token punctuation">[</span><span class="token punctuation">]</span> array<span class="token punctuation">;</span>

    <span class="token comment">// 获取数组引用</span>
    <span class="token keyword">final</span> <span class="token class-name">Object</span><span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token function">getArray</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">return</span> array<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    <span class="token comment">// 设置数组引用</span>
    <span class="token keyword">final</span> <span class="token keyword">void</span> <span class="token function">setArray</span><span class="token punctuation">(</span><span class="token class-name">Object</span><span class="token punctuation">[</span><span class="token punctuation">]</span> a<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        array <span class="token operator">=</span> a<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>CopyOnWriteArrayList</code> 的内部结构非常简单：使用 <code>ReentrantLock</code> 保证写操作的互斥性，使用数组存储元素。数组用 <code>volatile</code> 修饰，保证<strong>内存可见性</strong>——当某个线程对 <code>array</code> 重新赋值后，其他线程能立即看到新的数组引用。</p><p>关于为什么不直接用 <code>ArrayList</code> 的 <code>Collections.synchronizedList()</code> 包装：<code>synchronizedList</code> 对所有操作（包括读）都加锁，而 <code>CopyOnWriteArrayList</code> 的读操作<strong>完全不需要加锁</strong>，因为读操作操作的是不可变的数组快照。这使得它在读多写少的场景下性能远优于全局加锁的方案。</p><blockquote><p><strong>💡 核心提示</strong>：ReentrantLock 使用的是<strong>排它锁</strong>（互斥锁），同一时间只有一个线程能持有锁执行写操作。为什么不使用 <code>synchronized</code>？因为 <code>ReentrantLock</code> 支持公平锁、可中断获取锁、超时获取锁等更灵活的特性，虽然在这里只用到了基本的互斥功能，但统一使用 <code>ReentrantLock</code> 是 Doug Lea（JUC 包作者）的编码风格。</p></blockquote><h3 id="核心工作原理" tabindex="-1"><a class="header-anchor" href="#核心工作原理"><span>核心工作原理</span></a></h3>`,6)),t(a,{id:"mermaid-63",code:""}),n[2]||(n[2]=s(`<h2 id="初始化" tabindex="-1"><a class="header-anchor" href="#初始化"><span>初始化</span></a></h2><p>当我们调用 <code>CopyOnWriteArrayList</code> 的构造方法时，底层逻辑是怎么实现的？</p><div class="language-java line-numbers-mode" data-ext="java" data-title="java"><pre class="language-java"><code><span class="token class-name">List</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Integer</span><span class="token punctuation">&gt;</span></span> list <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">CopyOnWriteArrayList</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><code>CopyOnWriteArrayList</code> 初始化的时候，<strong>不支持指定数组长度</strong>。这是因为 <code>CopyOnWriteArrayList</code> 没有传统意义上的&quot;扩容&quot;概念——每次修改都会创建一个精确大小的新数组，不需要预留空间。</p><div class="language-java line-numbers-mode" data-ext="java" data-title="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token class-name">CopyOnWriteArrayList</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token function">setArray</span><span class="token punctuation">(</span><span class="token keyword">new</span> <span class="token class-name">Object</span><span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>初始化过程非常简单，就是创建了一个长度为 0 的空数组。</p><p>除了无参构造，<code>CopyOnWriteArrayList</code> 还支持从集合初始化：</p><div class="language-java line-numbers-mode" data-ext="java" data-title="java"><pre class="language-java"><code><span class="token comment">// 从现有集合初始化</span>
<span class="token class-name">List</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Integer</span><span class="token punctuation">&gt;</span></span> list <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">CopyOnWriteArrayList</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span><span class="token class-name">Arrays</span><span class="token punctuation">.</span><span class="token function">asList</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-java line-numbers-mode" data-ext="java" data-title="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token class-name">CopyOnWriteArrayList</span><span class="token punctuation">(</span><span class="token class-name">Collection</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token operator">?</span> <span class="token keyword">extends</span> <span class="token class-name">E</span><span class="token punctuation">&gt;</span></span> c<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token class-name">Object</span><span class="token punctuation">[</span><span class="token punctuation">]</span> elements<span class="token punctuation">;</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>c<span class="token punctuation">.</span><span class="token function">getClass</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">==</span> <span class="token class-name">CopyOnWriteArrayList</span><span class="token punctuation">.</span><span class="token keyword">class</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token comment">// 如果源也是 CopyOnWriteArrayList，直接获取其数组引用</span>
        elements <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token class-name">CopyOnWriteArrayList</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token operator">?</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">)</span> c<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">getArray</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
        <span class="token comment">// 否则将集合转换为数组</span>
        elements <span class="token operator">=</span> c<span class="token punctuation">.</span><span class="token function">toArray</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token comment">// 如果 toArray 返回的不是 Object[]，需要复制一份</span>
        <span class="token keyword">if</span> <span class="token punctuation">(</span>elements<span class="token punctuation">.</span><span class="token function">getClass</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">!=</span> <span class="token class-name">Object</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">.</span><span class="token keyword">class</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
            elements <span class="token operator">=</span> <span class="token class-name">Arrays</span><span class="token punctuation">.</span><span class="token function">copyOf</span><span class="token punctuation">(</span>elements<span class="token punctuation">,</span> elements<span class="token punctuation">.</span>length<span class="token punctuation">,</span> <span class="token class-name">Object</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">.</span><span class="token keyword">class</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
    <span class="token function">setArray</span><span class="token punctuation">(</span>elements<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这里有一个巧妙的设计：如果源集合本身就是 <code>CopyOnWriteArrayList</code>，直接复用其数组引用（因为数组本身是不可变的快照），避免了不必要的拷贝。如果 <code>toArray()</code> 返回的是特定类型数组（如 <code>Integer[]</code>），还需要额外拷贝一份转换为 <code>Object[]</code>，保证内部数组类型的一致性。</p><h2 id="添加元素" tabindex="-1"><a class="header-anchor" href="#添加元素"><span>添加元素</span></a></h2><p>再看一下往 <code>CopyOnWriteArrayList</code> 添加元素时，调用的 <code>add()</code> 方法源码实现：</p><div class="language-java line-numbers-mode" data-ext="java" data-title="java"><pre class="language-java"><code><span class="token comment">// 添加元素</span>
<span class="token keyword">public</span> <span class="token keyword">boolean</span> <span class="token function">add</span><span class="token punctuation">(</span><span class="token class-name">E</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// 加锁，保证写操作线程安全</span>
    <span class="token keyword">final</span> <span class="token class-name">ReentrantLock</span> lock <span class="token operator">=</span> <span class="token keyword">this</span><span class="token punctuation">.</span>lock<span class="token punctuation">;</span>
    lock<span class="token punctuation">.</span><span class="token function">lock</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

    <span class="token keyword">try</span> <span class="token punctuation">{</span>
        <span class="token comment">// 获取原数组引用</span>
        <span class="token class-name">Object</span><span class="token punctuation">[</span><span class="token punctuation">]</span> elements <span class="token operator">=</span> <span class="token function">getArray</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token keyword">int</span> len <span class="token operator">=</span> elements<span class="token punctuation">.</span>length<span class="token punctuation">;</span>
        <span class="token comment">// 创建一个新数组，长度为原数组长度+1，并把原数组元素拷贝到新数组</span>
        <span class="token class-name">Object</span><span class="token punctuation">[</span><span class="token punctuation">]</span> newElements <span class="token operator">=</span> <span class="token class-name">Arrays</span><span class="token punctuation">.</span><span class="token function">copyOf</span><span class="token punctuation">(</span>elements<span class="token punctuation">,</span> len <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token comment">// 将新元素放到新数组末尾</span>
        newElements<span class="token punctuation">[</span>len<span class="token punctuation">]</span> <span class="token operator">=</span> e<span class="token punctuation">;</span>
        <span class="token comment">// 用新数组替换原数组引用</span>
        <span class="token function">setArray</span><span class="token punctuation">(</span>newElements<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token keyword">return</span> <span class="token boolean">true</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span> <span class="token keyword">finally</span> <span class="token punctuation">{</span>
        <span class="token comment">// 释放锁</span>
        lock<span class="token punctuation">.</span><span class="token function">unlock</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>添加元素的流程：</p><ol><li>先使用 <code>ReentrantLock</code> 加锁，保证写操作的互斥性。</li><li>创建一个新数组，长度是原数组长度 +1，并把原数组元素拷贝到新数组。</li><li>在新数组末尾位置赋值新元素。</li><li>使用 <code>setArray()</code> 将新数组引用赋值给 <code>volatile</code> 修饰的 <code>array</code>。</li><li>释放锁。</li></ol><p><code>add()</code> 方法并没有在原数组上进行修改，而是创建新数组，修改完成后用新数组替换原数组。这有两个目的：一是利用 <code>volatile</code> 的可见性——只有重新对 <code>array</code> 赋值（而不是修改数组内容），其他线程才能感知到变化；二是保证读操作的快照语义——正在读的线程引用的仍然是旧数组，不受影响。</p><blockquote><p><strong>💡 核心提示</strong>：为什么要在 <code>finally</code> 块中释放锁？这是使用 <code>ReentrantLock</code> 的<strong>最佳实践</strong>。如果在 try 块中发生异常，没有 finally 块会导致锁永远不释放，其他等待该锁的线程将永久阻塞，形成<strong>死锁</strong>。Doug Lea 的源码严格遵守了这一规范。</p></blockquote><p>还有一个需要注意的点是，每次添加元素都会创建一个新数组，涉及完整的数组拷贝。当数组较大时，性能消耗较为明显。所以 <code>CopyOnWriteArrayList</code> 适用于<strong>读多写少</strong>的场景，如果存在较多的写操作，性能是需要重点考虑的因素。</p><p>除了尾插的 <code>add(e)</code>，<code>CopyOnWriteArrayList</code> 还支持在指定位置插入的 <code>add(index, element)</code>：</p><div class="language-java line-numbers-mode" data-ext="java" data-title="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">add</span><span class="token punctuation">(</span><span class="token keyword">int</span> index<span class="token punctuation">,</span> <span class="token class-name">E</span> element<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">final</span> <span class="token class-name">ReentrantLock</span> lock <span class="token operator">=</span> <span class="token keyword">this</span><span class="token punctuation">.</span>lock<span class="token punctuation">;</span>
    lock<span class="token punctuation">.</span><span class="token function">lock</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">try</span> <span class="token punctuation">{</span>
        <span class="token class-name">Object</span><span class="token punctuation">[</span><span class="token punctuation">]</span> elements <span class="token operator">=</span> <span class="token function">getArray</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token keyword">int</span> len <span class="token operator">=</span> elements<span class="token punctuation">.</span>length<span class="token punctuation">;</span>
        <span class="token comment">// 检查下标合法性</span>
        <span class="token keyword">if</span> <span class="token punctuation">(</span>index <span class="token operator">&gt;</span> len <span class="token operator">||</span> index <span class="token operator">&lt;</span> <span class="token number">0</span><span class="token punctuation">)</span>
            <span class="token keyword">throw</span> <span class="token keyword">new</span> <span class="token class-name">IndexOutOfBoundsException</span><span class="token punctuation">(</span><span class="token string">&quot;Index: &quot;</span> <span class="token operator">+</span> index <span class="token operator">+</span> <span class="token string">&quot;, Size: &quot;</span> <span class="token operator">+</span> len<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token class-name">Object</span><span class="token punctuation">[</span><span class="token punctuation">]</span> newElements<span class="token punctuation">;</span>
        <span class="token keyword">int</span> numMoved <span class="token operator">=</span> len <span class="token operator">-</span> index<span class="token punctuation">;</span>
        <span class="token keyword">if</span> <span class="token punctuation">(</span>numMoved <span class="token operator">==</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
            <span class="token comment">// 插入到末尾，同 add(e)</span>
            newElements <span class="token operator">=</span> <span class="token class-name">Arrays</span><span class="token punctuation">.</span><span class="token function">copyOf</span><span class="token punctuation">(</span>elements<span class="token punctuation">,</span> len <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
            <span class="token comment">// 插入到中间位置，需要分两段拷贝</span>
            newElements <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Object</span><span class="token punctuation">[</span>len <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
            <span class="token class-name">System</span><span class="token punctuation">.</span><span class="token function">arraycopy</span><span class="token punctuation">(</span>elements<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> newElements<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> index<span class="token punctuation">)</span><span class="token punctuation">;</span>
            <span class="token class-name">System</span><span class="token punctuation">.</span><span class="token function">arraycopy</span><span class="token punctuation">(</span>elements<span class="token punctuation">,</span> index<span class="token punctuation">,</span> newElements<span class="token punctuation">,</span> index <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">,</span> numMoved<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span>
        newElements<span class="token punctuation">[</span>index<span class="token punctuation">]</span> <span class="token operator">=</span> element<span class="token punctuation">;</span>
        <span class="token function">setArray</span><span class="token punctuation">(</span>newElements<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span> <span class="token keyword">finally</span> <span class="token punctuation">{</span>
        lock<span class="token punctuation">.</span><span class="token function">unlock</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>插入到中间位置时，需要将原数组分成两段：<code>index</code> 之前的元素直接拷贝，<code>index</code> 及之后的元素向后错一位拷贝。</p><h2 id="删除元素" tabindex="-1"><a class="header-anchor" href="#删除元素"><span>删除元素</span></a></h2><p>再看一下删除元素的方法 <code>remove()</code> 的源码：</p><div class="language-java line-numbers-mode" data-ext="java" data-title="java"><pre class="language-java"><code><span class="token comment">// 按下标删除元素</span>
<span class="token keyword">public</span> <span class="token class-name">E</span> <span class="token function">remove</span><span class="token punctuation">(</span><span class="token keyword">int</span> index<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// 加锁，保证写操作线程安全</span>
    <span class="token keyword">final</span> <span class="token class-name">ReentrantLock</span> lock <span class="token operator">=</span> <span class="token keyword">this</span><span class="token punctuation">.</span>lock<span class="token punctuation">;</span>
    lock<span class="token punctuation">.</span><span class="token function">lock</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

    <span class="token keyword">try</span> <span class="token punctuation">{</span>
        <span class="token comment">// 获取原数组引用</span>
        <span class="token class-name">Object</span><span class="token punctuation">[</span><span class="token punctuation">]</span> elements <span class="token operator">=</span> <span class="token function">getArray</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token keyword">int</span> len <span class="token operator">=</span> elements<span class="token punctuation">.</span>length<span class="token punctuation">;</span>
        <span class="token class-name">E</span> oldValue <span class="token operator">=</span> <span class="token function">get</span><span class="token punctuation">(</span>elements<span class="token punctuation">,</span> index<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token comment">// 计算需要移动的元素个数</span>
        <span class="token keyword">int</span> numMoved <span class="token operator">=</span> len <span class="token operator">-</span> index <span class="token operator">-</span> <span class="token number">1</span><span class="token punctuation">;</span>
        <span class="token keyword">if</span> <span class="token punctuation">(</span>numMoved <span class="token operator">==</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
            <span class="token comment">// 删除的是数组末尾元素，直接拷贝前 len-1 个</span>
            <span class="token function">setArray</span><span class="token punctuation">(</span><span class="token class-name">Arrays</span><span class="token punctuation">.</span><span class="token function">copyOf</span><span class="token punctuation">(</span>elements<span class="token punctuation">,</span> len <span class="token operator">-</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
            <span class="token comment">// 创建新数组，长度是原数组长度-1</span>
            <span class="token class-name">Object</span><span class="token punctuation">[</span><span class="token punctuation">]</span> newElements <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Object</span><span class="token punctuation">[</span>len <span class="token operator">-</span> <span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
            <span class="token comment">// 把原数组下标前后两段的元素都拷贝到新数组（跳过被删除的元素）</span>
            <span class="token class-name">System</span><span class="token punctuation">.</span><span class="token function">arraycopy</span><span class="token punctuation">(</span>elements<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> newElements<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> index<span class="token punctuation">)</span><span class="token punctuation">;</span>
            <span class="token class-name">System</span><span class="token punctuation">.</span><span class="token function">arraycopy</span><span class="token punctuation">(</span>elements<span class="token punctuation">,</span> index <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">,</span> newElements<span class="token punctuation">,</span> index<span class="token punctuation">,</span>
                numMoved<span class="token punctuation">)</span><span class="token punctuation">;</span>
            <span class="token comment">// 替换原数组引用</span>
            <span class="token function">setArray</span><span class="token punctuation">(</span>newElements<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span>
        <span class="token keyword">return</span> oldValue<span class="token punctuation">;</span>
    <span class="token punctuation">}</span> <span class="token keyword">finally</span> <span class="token punctuation">{</span>
        <span class="token comment">// 释放锁</span>
        lock<span class="token punctuation">.</span><span class="token function">unlock</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>删除元素的流程：</p><ol><li>先使用 <code>ReentrantLock</code> 加锁。</li><li>创建一个新数组，长度是原数组长度 -1。</li><li>把原数组中剩余元素（不包含需要删除的元素）拷贝到新数组。删除中间元素时，使用 <code>System.arraycopy</code> 分两段拷贝：<code>index</code> 之前和 <code>index+1</code> 之后。</li><li>使用新数组替换掉原数组引用。</li><li>释放锁。</li></ol><p>根据对象值删除元素的 <code>remove(Object o)</code> 方法源码与之类似：先遍历数组找到目标元素的下标，然后转为下标删除。</p><h2 id="批量删除" tabindex="-1"><a class="header-anchor" href="#批量删除"><span>批量删除</span></a></h2><p>再看一下批量删除元素方法 <code>removeAll()</code> 的源码：</p><div class="language-java line-numbers-mode" data-ext="java" data-title="java"><pre class="language-java"><code><span class="token comment">// 批量删除元素</span>
<span class="token keyword">public</span> <span class="token keyword">boolean</span> <span class="token function">removeAll</span><span class="token punctuation">(</span><span class="token class-name">Collection</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token operator">?</span><span class="token punctuation">&gt;</span></span> c<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// 参数判空</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>c <span class="token operator">==</span> <span class="token keyword">null</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">throw</span> <span class="token keyword">new</span> <span class="token class-name">NullPointerException</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    <span class="token comment">// 加锁，保证写操作线程安全</span>
    <span class="token keyword">final</span> <span class="token class-name">ReentrantLock</span> lock <span class="token operator">=</span> <span class="token keyword">this</span><span class="token punctuation">.</span>lock<span class="token punctuation">;</span>
    lock<span class="token punctuation">.</span><span class="token function">lock</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

    <span class="token keyword">try</span> <span class="token punctuation">{</span>
        <span class="token comment">// 获取原数组引用</span>
        <span class="token class-name">Object</span><span class="token punctuation">[</span><span class="token punctuation">]</span> elements <span class="token operator">=</span> <span class="token function">getArray</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token keyword">int</span> len <span class="token operator">=</span> elements<span class="token punctuation">.</span>length<span class="token punctuation">;</span>
        <span class="token keyword">if</span> <span class="token punctuation">(</span>len <span class="token operator">!=</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
            <span class="token comment">// 创建临时数组，长度暂时使用原数组长度（因为不知道要保留多少元素）</span>
            <span class="token class-name">Object</span><span class="token punctuation">[</span><span class="token punctuation">]</span> temp <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Object</span><span class="token punctuation">[</span>len<span class="token punctuation">]</span><span class="token punctuation">;</span>
            <span class="token comment">// newlen 表示新数组中实际元素个数</span>
            <span class="token keyword">int</span> newlen <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>
            <span class="token comment">// 遍历原数组，把需要保留的元素放到临时数组中</span>
            <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> len<span class="token punctuation">;</span> <span class="token operator">++</span>i<span class="token punctuation">)</span> <span class="token punctuation">{</span>
                <span class="token class-name">Object</span> element <span class="token operator">=</span> elements<span class="token punctuation">[</span>i<span class="token punctuation">]</span><span class="token punctuation">;</span>
                <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span>c<span class="token punctuation">.</span><span class="token function">contains</span><span class="token punctuation">(</span>element<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
                    temp<span class="token punctuation">[</span>newlen<span class="token operator">++</span><span class="token punctuation">]</span> <span class="token operator">=</span> element<span class="token punctuation">;</span>
                <span class="token punctuation">}</span>
            <span class="token punctuation">}</span>
            <span class="token comment">// 如果新数组长度与原数组不同（有元素被删除），就截断空白并覆盖原数组引用</span>
            <span class="token keyword">if</span> <span class="token punctuation">(</span>newlen <span class="token operator">!=</span> len<span class="token punctuation">)</span> <span class="token punctuation">{</span>
                <span class="token function">setArray</span><span class="token punctuation">(</span><span class="token class-name">Arrays</span><span class="token punctuation">.</span><span class="token function">copyOf</span><span class="token punctuation">(</span>temp<span class="token punctuation">,</span> newlen<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
                <span class="token keyword">return</span> <span class="token boolean">true</span><span class="token punctuation">;</span>
            <span class="token punctuation">}</span>
        <span class="token punctuation">}</span>
        <span class="token keyword">return</span> <span class="token boolean">false</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span> <span class="token keyword">finally</span> <span class="token punctuation">{</span>
        <span class="token comment">// 释放锁</span>
        lock<span class="token punctuation">.</span><span class="token function">unlock</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>批量删除的流程与单个删除类似：</p><ol><li>加锁。</li><li>创建临时数组，长度暂时使用原数组长度（因为不知道要删除多少个元素）。</li><li>遍历原数组，把不需要删除的元素放到临时数组中。</li><li>用 <code>Arrays.copyOf(temp, newlen)</code> 截断临时数组中的空白部分，再替换原数组引用。</li><li>释放锁。</li></ol><p>如果遇到需要一次删除多个元素的场景，尽量使用 <code>removeAll()</code> 方法，因为它只涉及<strong>一次</strong>数组拷贝，性能比逐个调用 <code>remove()</code> 好得多（逐个删除每次都要创建新数组并拷贝）。</p><h2 id="并发修改问题" tabindex="-1"><a class="header-anchor" href="#并发修改问题"><span>并发修改问题</span></a></h2><p>当遍历 <code>CopyOnWriteArrayList</code> 的过程中，同时增删其中的元素，会发生什么情况？测试一下：</p><div class="language-java line-numbers-mode" data-ext="java" data-title="java"><pre class="language-java"><code><span class="token keyword">import</span> <span class="token import"><span class="token namespace">java<span class="token punctuation">.</span>util<span class="token punctuation">.</span></span><span class="token class-name">List</span></span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token import"><span class="token namespace">java<span class="token punctuation">.</span>util<span class="token punctuation">.</span>concurrent<span class="token punctuation">.</span></span><span class="token class-name">CopyOnWriteArrayList</span></span><span class="token punctuation">;</span>

<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Test</span> <span class="token punctuation">{</span>

    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token class-name">List</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Integer</span><span class="token punctuation">&gt;</span></span> list <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">CopyOnWriteArrayList</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        list<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        list<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        list<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        list<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token comment">// 遍历 ArrayList</span>
        <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token class-name">Integer</span> key <span class="token operator">:</span> list<span class="token punctuation">)</span> <span class="token punctuation">{</span>
            <span class="token comment">// 判断如果元素等于2，则删除</span>
            <span class="token keyword">if</span> <span class="token punctuation">(</span>key<span class="token punctuation">.</span><span class="token function">equals</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
                list<span class="token punctuation">.</span><span class="token function">remove</span><span class="token punctuation">(</span>key<span class="token punctuation">)</span><span class="token punctuation">;</span>
            <span class="token punctuation">}</span>
        <span class="token punctuation">}</span>
        <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span>list<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>输出结果：</p><div class="language-text line-numbers-mode" data-ext="text" data-title="text"><pre class="language-text"><code>[1, 3]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>不但没有抛出异常，还把 <code>CopyOnWriteArrayList</code> 中重复的元素也都删除了。</p><p>原因是 <code>CopyOnWriteArrayList</code> 重写了迭代器，拷贝了一份原数组的<strong>快照</strong>，在快照数组上进行遍历。这样做的优点是：其他线程对数组的修改不影响当前遍历；缺点是：遍历过程中<strong>无法感知</strong>其他线程对数组的最新修改。这就是所谓的<strong>弱一致性</strong>（weakly consistent）语义——有得必有失。</p><p>下面是迭代器的源码实现：</p><div class="language-java line-numbers-mode" data-ext="java" data-title="java"><pre class="language-java"><code><span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token keyword">class</span> <span class="token class-name">COWIterator</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">E</span><span class="token punctuation">&gt;</span></span> <span class="token keyword">implements</span> <span class="token class-name">ListIterator</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">E</span><span class="token punctuation">&gt;</span></span> <span class="token punctuation">{</span>
    <span class="token doc-comment comment">/**
     * 创建迭代器时的数组快照
     */</span>
    <span class="token keyword">private</span> <span class="token keyword">final</span> <span class="token class-name">Object</span><span class="token punctuation">[</span><span class="token punctuation">]</span> snapshot<span class="token punctuation">;</span>
    <span class="token doc-comment comment">/**
     * 迭代游标
     */</span>
    <span class="token keyword">private</span> <span class="token keyword">int</span> cursor<span class="token punctuation">;</span>

    <span class="token keyword">private</span> <span class="token class-name">COWIterator</span><span class="token punctuation">(</span><span class="token class-name">Object</span><span class="token punctuation">[</span><span class="token punctuation">]</span> elements<span class="token punctuation">,</span> <span class="token keyword">int</span> initialCursor<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        cursor <span class="token operator">=</span> initialCursor<span class="token punctuation">;</span>
        snapshot <span class="token operator">=</span> elements<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">public</span> <span class="token keyword">boolean</span> <span class="token function">hasNext</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">return</span> cursor <span class="token operator">&lt;</span> snapshot<span class="token punctuation">.</span>length<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token comment">// 迭代下个元素</span>
    <span class="token keyword">public</span> <span class="token class-name">E</span> <span class="token function">next</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span><span class="token function">hasNext</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
            <span class="token keyword">throw</span> <span class="token keyword">new</span> <span class="token class-name">NoSuchElementException</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token keyword">return</span> <span class="token punctuation">(</span><span class="token class-name">E</span><span class="token punctuation">)</span> snapshot<span class="token punctuation">[</span>cursor<span class="token operator">++</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token comment">// 以下操作都不支持（因为迭代器操作的是快照，无法反映到原数组）</span>
    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">remove</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">throw</span> <span class="token keyword">new</span> <span class="token class-name">UnsupportedOperationException</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">set</span><span class="token punctuation">(</span><span class="token class-name">E</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">throw</span> <span class="token keyword">new</span> <span class="token class-name">UnsupportedOperationException</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">add</span><span class="token punctuation">(</span><span class="token class-name">E</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">throw</span> <span class="token keyword">new</span> <span class="token class-name">UnsupportedOperationException</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>可以看到，<code>COWIterator</code> 的 <code>remove()</code>、<code>set()</code>、<code>add()</code> 方法都直接抛出 <code>UnsupportedOperationException</code>。这是因为迭代器持有的是快照数组的引用，对快照的修改无法反映到原数组中。如果需要修改，应该直接调用 <code>CopyOnWriteArrayList</code> 自身的方法。</p><h2 id="生产环境避坑指南" tabindex="-1"><a class="header-anchor" href="#生产环境避坑指南"><span>生产环境避坑指南</span></a></h2><p>基于上述源码分析，以下是 CopyOnWriteArrayList 在生产环境中常见的陷阱：</p><table><thead><tr><th style="text-align:left;">陷阱</th><th style="text-align:left;">现象</th><th style="text-align:left;">解决方案</th></tr></thead><tbody><tr><td style="text-align:left;">大数组频繁写操作</td><td style="text-align:left;">每次写都要拷贝全数组，CPU 和内存双重消耗</td><td style="text-align:left;">改用 <code>Collections.synchronizedList()</code> 或 <code>ReentrantLock</code> + <code>ArrayList</code></td></tr><tr><td style="text-align:left;">遍历不感知最新修改</td><td style="text-align:left;">迭代器拿到的是旧快照，看不到写入的最新元素</td><td style="text-align:left;">如果业务需要强一致遍历语义，不要用 COWAL</td></tr><tr><td style="text-align:left;">迭代器不支持修改</td><td style="text-align:left;"><code>iterator.remove()</code> / <code>add()</code> / <code>set()</code> 直接抛异常</td><td style="text-align:left;">直接调用 <code>CopyOnWriteArrayList</code> 自身的方法</td></tr><tr><td style="text-align:left;">内存峰值 + GC 压力</td><td style="text-align:left;">写操作创建大量临时数组，短时间内存翻倍</td><td style="text-align:left;">评估数组大小和写入频率，必要时改用其他方案</td></tr><tr><td style="text-align:left;">误以为完全替代 ArrayList</td><td style="text-align:left;">COWAL 是特殊场景的专用工具，不是 ArrayList 的通用替代</td><td style="text-align:left;">非读多写少的线程安全场景不要用它</td></tr></tbody></table><h2 id="线程安全方案对比" tabindex="-1"><a class="header-anchor" href="#线程安全方案对比"><span>线程安全方案对比</span></a></h2><table><thead><tr><th style="text-align:left;">方案</th><th style="text-align:left;">读操作</th><th style="text-align:left;">写操作</th><th style="text-align:left;">迭代器语义</th><th style="text-align:left;">适用场景</th></tr></thead><tbody><tr><td style="text-align:left;"><code>CopyOnWriteArrayList</code></td><td style="text-align:left;"><strong>无锁</strong>，O(1)</td><td style="text-align:left;">O(n)，全量拷贝</td><td style="text-align:left;"><strong>fail-safe</strong>（快照）</td><td style="text-align:left;">读极多写极少（事件监听器、配置列表）</td></tr><tr><td style="text-align:left;"><code>Collections.synchronizedList()</code></td><td style="text-align:left;">加锁，O(1)</td><td style="text-align:left;">加锁，O(1) 平均</td><td style="text-align:left;"><strong>fail-fast</strong></td><td style="text-align:left;">读写均衡的线程安全场景</td></tr><tr><td style="text-align:left;"><code>Vector</code></td><td style="text-align:left;">加锁，O(1)</td><td style="text-align:left;">加锁，O(1) 平均</td><td style="text-align:left;"><strong>fail-fast</strong></td><td style="text-align:left;"><strong>不推荐</strong>，遗留类</td></tr></tbody></table><h2 id="总结" tabindex="-1"><a class="header-anchor" href="#总结"><span>总结</span></a></h2><p>现在可以回答文章开头提出的问题了：</p><ol><li><p><strong>CopyOnWriteArrayList 初始容量是多少？</strong></p><p>答案：是 0。无参构造直接创建长度为 0 的空数组。</p></li><li><p><strong>CopyOnWriteArrayList 是怎么进行扩容的？</strong></p><p>答案：<code>CopyOnWriteArrayList</code> 没有传统意义上的&quot;扩容&quot;概念。每次写操作（add/remove/set）都创建一个精确大小的新数组，拷贝旧数据，然后用新数组替换旧数组引用。</p></li><li><p><strong>CopyOnWriteArrayList 是怎么保证线程安全的？</strong></p><p>答案：</p><ul><li>使用 <code>ReentrantLock</code> 加锁，保证同一时间只有一个线程在执行写操作。</li><li>使用 <code>volatile</code> 关键字修饰数组引用，保证写线程对新数组的赋值对其他线程立即可见。</li><li>读操作完全无锁——读的是不可变的数组快照，天然线程安全。</li></ul></li></ol><h3 id="关键操作时间复杂度对比" tabindex="-1"><a class="header-anchor" href="#关键操作时间复杂度对比"><span>关键操作时间复杂度对比</span></a></h3><table><thead><tr><th style="text-align:left;">操作</th><th style="text-align:left;">方法</th><th style="text-align:left;">时间复杂度</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">读取</td><td style="text-align:left;"><code>get(int index)</code></td><td style="text-align:left;">O(1)</td><td style="text-align:left;">直接数组下标访问，无需加锁</td></tr><tr><td style="text-align:left;">尾插</td><td style="text-align:left;"><code>add(E e)</code></td><td style="text-align:left;">O(n)</td><td style="text-align:left;">创建新数组 + 拷贝全部旧元素</td></tr><tr><td style="text-align:left;">中间插入</td><td style="text-align:left;"><code>add(int index, E e)</code></td><td style="text-align:left;">O(n)</td><td style="text-align:left;">创建新数组 + 分两段拷贝</td></tr><tr><td style="text-align:left;">删除</td><td style="text-align:left;"><code>remove(int index)</code></td><td style="text-align:left;">O(n)</td><td style="text-align:left;">创建新数组 + 拷贝剩余元素</td></tr><tr><td style="text-align:left;">批量删除</td><td style="text-align:left;"><code>removeAll(Collection)</code></td><td style="text-align:left;">O(n*m)</td><td style="text-align:left;">n 为原数组长度，m 为待删除集合大小</td></tr><tr><td style="text-align:left;">遍历</td><td style="text-align:left;"><code>iterator()</code> / <code>forEach</code></td><td style="text-align:left;">O(n)</td><td style="text-align:left;">遍历快照数组，无锁</td></tr><tr><td style="text-align:left;">查找</td><td style="text-align:left;"><code>contains()</code> / <code>indexOf()</code></td><td style="text-align:left;">O(n)</td><td style="text-align:left;">线性遍历数组</td></tr></tbody></table><h3 id="使用建议" tabindex="-1"><a class="header-anchor" href="#使用建议"><span>使用建议</span></a></h3><ol><li><strong>读多写少场景首选</strong>：<code>CopyOnWriteArrayList</code> 的读操作完全无锁，多个线程并发读取时性能极佳。但每次写操作都要创建新数组并拷贝全部旧元素，写操作成本为 O(n)。如果写操作频繁，性能会急剧下降。典型适用场景：配置列表、白名单、事件监听器列表等。</li><li><strong>遍历不感知最新修改</strong>：迭代器持有创建时的数组快照，遍历时不会抛出 <code>ConcurrentModificationException</code>，但也看不到其他线程的最新修改。如果业务需要强一致的遍历语义，不适合使用 <code>CopyOnWriteArrayList</code>。</li><li><strong>迭代器不支持修改操作</strong>：<code>COWIterator</code> 的 <code>remove()</code>、<code>set()</code>、<code>add()</code> 都会抛出 <code>UnsupportedOperationException</code>。需要在遍历时删除元素的话，应该直接调用 <code>CopyOnWriteArrayList.remove()</code> 方法。</li><li><strong>注意内存峰值</strong>：每次写操作都会创建新数组，在写操作频繁的极端情况下，短时间内会产生大量临时数组对象，可能引发频繁的 GC。如果预估数组较大且有一定写入频率，需要考虑内存和 GC 的影响。</li></ol><h3 id="行动清单" tabindex="-1"><a class="header-anchor" href="#行动清单"><span>行动清单</span></a></h3><ol><li><strong>检查点</strong>：确认项目中 <code>CopyOnWriteArrayList</code> 的使用场景确实是&quot;读多写少&quot;，如果写操作频繁，应替换为 <code>Collections.synchronizedList()</code>。</li><li><strong>检查点</strong>：确认遍历逻辑是否容忍弱一致性语义。如果遍历时需要看到最新数据，不要用 COWAL。</li><li><strong>避坑</strong>：不要在 COWAL 的迭代器上调用 <code>remove()</code>/<code>add()</code>/<code>set()</code>——直接抛 <code>UnsupportedOperationException</code>。</li><li><strong>优化建议</strong>：如果初始化时已知元素集合，使用 <code>new CopyOnWriteArrayList&lt;&gt;(collection)</code> 构造方法，避免后续逐个 add 导致的多次全量拷贝。</li><li><strong>避坑</strong>：大容量 + 高频写入场景会导致严重的内存抖动和 GC 压力，建议改用 <code>ReentrantLock</code> + <code>ArrayList</code> 的组合。</li><li><strong>扩展阅读</strong>：推荐阅读《Java Concurrency in Practice》第5章（并发集合）、第5.2.3节（CopyOnWriteArrayList 源码分析）。</li></ol>`,57))])}const k=e(l,[["render",i],["__file","CopyOnWriteArrayList.html.vue"]]),m=JSON.parse('{"path":"/list/CopyOnWriteArrayList.html","title":"","lang":"zh-CN","frontmatter":{"description":"引言 一个读多写少的 List，用 synchronized 加锁就完了？ 加锁确实能保证线程安全，但代价是所有操作都串行化——读操作也要排队等待写操作释放锁。在读远多于写的场景下（如配置列表、白名单、路由表），这是不必要的性能浪费。 CopyOnWriteArrayList 提供了一种更优雅的思路：写时复制。读操作完全无锁、零等待，写操作在副本上进行...","head":[["meta",{"property":"og:url","content":"https://vuepress-theme-hope-docs-demo.netlify.app/list/CopyOnWriteArrayList.html"}],["meta",{"property":"og:site_name","content":"Java八股文网"}],["meta",{"property":"og:description","content":"引言 一个读多写少的 List，用 synchronized 加锁就完了？ 加锁确实能保证线程安全，但代价是所有操作都串行化——读操作也要排队等待写操作释放锁。在读远多于写的场景下（如配置列表、白名单、路由表），这是不必要的性能浪费。 CopyOnWriteArrayList 提供了一种更优雅的思路：写时复制。读操作完全无锁、零等待，写操作在副本上进行..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-04-18T07:28:17.000Z"}],["meta",{"property":"article:author","content":"Mr.Hope"}],["meta",{"property":"article:modified_time","content":"2026-04-18T07:28:17.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-04-18T07:28:17.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Mr.Hope\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"引言","slug":"引言","link":"#引言","children":[]},{"level":2,"title":"简介","slug":"简介","link":"#简介","children":[{"level":3,"title":"类图架构","slug":"类图架构","link":"#类图架构","children":[]},{"level":3,"title":"核心工作原理","slug":"核心工作原理","link":"#核心工作原理","children":[]}]},{"level":2,"title":"初始化","slug":"初始化","link":"#初始化","children":[]},{"level":2,"title":"添加元素","slug":"添加元素","link":"#添加元素","children":[]},{"level":2,"title":"删除元素","slug":"删除元素","link":"#删除元素","children":[]},{"level":2,"title":"批量删除","slug":"批量删除","link":"#批量删除","children":[]},{"level":2,"title":"并发修改问题","slug":"并发修改问题","link":"#并发修改问题","children":[]},{"level":2,"title":"生产环境避坑指南","slug":"生产环境避坑指南","link":"#生产环境避坑指南","children":[]},{"level":2,"title":"线程安全方案对比","slug":"线程安全方案对比","link":"#线程安全方案对比","children":[]},{"level":2,"title":"总结","slug":"总结","link":"#总结","children":[{"level":3,"title":"关键操作时间复杂度对比","slug":"关键操作时间复杂度对比","link":"#关键操作时间复杂度对比","children":[]},{"level":3,"title":"使用建议","slug":"使用建议","link":"#使用建议","children":[]},{"level":3,"title":"行动清单","slug":"行动清单","link":"#行动清单","children":[]}]}],"git":{"createdTime":1745907928000,"updatedTime":1776497297000,"contributors":[{"name":"Yideng","email":"oointer@163.com","commits":3}]},"readingTime":{"minutes":14.5,"words":4349},"filePathRelative":"list/CopyOnWriteArrayList.md","localizedDate":"2025年4月29日","autoDesc":true}');export{k as comp,m as data};
